// Lee body del webhook, normaliza DNI/phone/strings, valida required.
const raw = $input.first().json.body || $input.first().json;
if (!raw || typeof raw !== 'object') {
  throw new Error('invalid_body');
}

function normDni(s) { return String(s ?? '').replace(/\D/g, ''); }
function normPhone(s) {
  let v = String(s ?? '').replace(/[^\d+]/g, '');
  if (!v) return '';
  if (v.startsWith('+')) return v;
  if (v.startsWith('549')) return '+' + v;
  if (v.startsWith('54')) return '+' + v;
  if (v.startsWith('0')) v = v.slice(1);
  if (v.startsWith('15')) v = v.slice(2);
  return '+549' + v;
}
function titleCase(s) {
  return String(s ?? '').toLowerCase().replace(/\b\w/g, c => c.toUpperCase()).trim();
}
function num(s) { const n = Number(s); return Number.isFinite(n) ? n : 0; }
function str(s) { return String(s ?? '').trim(); }

const required = ['dni','first_name','last_name','phone','birth_date',
  'address_line','locality','province','postal_code',
  'requested_amount_ars','requested_installments','payment_frequency',
  'housing_status','occupation'];
const missing = required.filter(k => !raw[k] || String(raw[k]).trim() === '');
if (missing.length) {
  throw new Error('missing_required: ' + missing.join(','));
}

const dni = normDni(raw.dni);
if (dni.length < 7 || dni.length > 9) {
  throw new Error('invalid_dni');
}

const p = {
  // Identidad
  dni,
  first_name: titleCase(raw.first_name),
  last_name:  titleCase(raw.last_name),
  email:      str(raw.email).toLowerCase() || null,
  phone:      normPhone(raw.phone),
  birth_date: str(raw.birth_date), // YYYY-MM-DD
  // Domicilio
  address_line: str(raw.address_line),
  locality:     titleCase(raw.locality),
  province:     titleCase(raw.province),
  postal_code:  str(raw.postal_code).toUpperCase(),
  // Crédito
  requested_amount_ars:   num(raw.requested_amount_ars),
  requested_installments: Math.max(1, Math.floor(num(raw.requested_installments))),
  payment_frequency:      str(raw.payment_frequency),
  estimated_installment_ars: num(raw.estimated_installment_ars),
  declared_income_ars:    num(raw.declared_income_ars),
  // Ocupación / Vivienda
  housing_status:    str(raw.housing_status),
  occupation:        str(raw.occupation),
  occupation_detail: str(raw.occupation_detail),
  // Garante
  guarantor_name:     str(raw.guarantor_name),
  guarantor_phone:    raw.guarantor_phone ? normPhone(raw.guarantor_phone) : '',
  guarantor_relation: str(raw.guarantor_relation),
  // Marketing
  marketing_consent: !!raw.marketing_consent,
  // Shopify product
  shop:           str(raw.shop) || 'domu',
  source:         str(raw.source) || 'shopify_liquid',
  product_id:     str(raw.product_id),
  variant_id:     str(raw.variant_id),
  product_title:  str(raw.product_title),
  product_handle: str(raw.product_handle),
  unit_price_ars: num(raw.unit_price_ars),
  quantity:       Math.max(1, Math.floor(num(raw.quantity) || 1)),
  cart_token:     str(raw.cart_token),
  cart_total_ars: num(raw.cart_total_ars),
  cart_summary:   str(raw.cart_summary),
  // UTM
  utm_source:    str(raw.utm_source),
  utm_medium:    str(raw.utm_medium),
  utm_campaign:  str(raw.utm_campaign),
  utm_content:   str(raw.utm_content),
  utm_term:      str(raw.utm_term),
  referrer_url:  str(raw.referrer_url),
  landing_url:   str(raw.landing_url),
  // Idempotency: el form genera UUID en client; si no vino, lo armamos del dni+timestamp
  idempotency_key: str(raw.idempotency_key) || (dni + '-' + Date.now()),
};

// raw_payload guarda el JSON completo del form como vino (sin normalizar)
p._raw_payload = JSON.stringify(raw);

return [{ json: p }];

// Merge: payload validado + client_id de PG + zone_status
const p = $('Validate + Normalize').first().json;
const clientRow = $('PG: Upsert client').first().json;
const zoneRow = $('PG: Check zone').first().json;
const client_id = clientRow.id;
const zone_status = zoneRow?.zone_status || 'needs_review';
const zone_id = zoneRow?.zone_id || null;
return [{ json: { ...p, client_id, zone_status, zone_id } }];

const p = $('Merge: payload + client_id + zone').first().json;
const app = $('PG: Insert credit_application').first().json;
return [{
  json: {
    ...p,
    application_id: app.id,
    application_code: app.application_code,
    application_status: 'submitted',
    created_at: app.created_at,
  }
}];

const p = $json;

function esc(s) { return String(s ?? '').replace(/([_*\[\]()~`>#+\-=|{}.!])/g, '\\$1'); }
function money(n) { const v = Math.round(Number(n) || 0); return '$' + v.toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.'); }
function fmtDni(d) { return String(d || '').replace(/(\d{2,3})(?=(\d{3})+$)/g, '$1.'); }

const E = { check: '✅', warn: '⚠️', cross: '❌', speech: '💬', clipboard: '📋' };

const housingMap = {
  owned: 'Vivienda propia', rented: 'Vivienda alquilada',
  family: 'Vivienda familiar / cedida', other: 'Otra vivienda',
};
const occupationMap = {
  employed_registered:      'Empleado en relación de dependencia',
  self_employed_registered: 'Monotributista / Autónomo',
  unregistered:             'Trabajo informal',
  retired:                  'Jubilado / Pensionado',
  homemaker:                'Ama de casa',
  student:                  'Estudiante',
  informal:                 'Trabajos por cuenta propia',
  other:                    'Otra ocupación',
};
const freqMap = { daily: 'diarias', weekly: 'semanales', monthly: 'mensuales' };

function zoneInfo(z) {
  if (z === 'in_zone')      return { e: E.check, label: 'En zona' };
  if (z === 'needs_review') return { e: E.warn,  label: 'Revisar manualmente' };
  return { e: E.cross, label: 'Fuera de zona' };
}

const code = p.application_code || 'unknown';
const nombre = `${p.first_name || ''} ${p.last_name || ''}`.trim() || 'Sin nombre';
const dni = fmtDni(p.dni);
const phone = p.phone || '';
const email = p.email || '';
const monto = money(p.requested_amount_ars);
const cuotas = p.requested_installments || '?';
const freq = freqMap[p.payment_frequency] || p.payment_frequency || '';
const ingreso = p.declared_income_ars ? money(p.declared_income_ars) : null;
const housing = housingMap[p.housing_status] || p.housing_status || '';
const occupation = occupationMap[p.occupation] || p.occupation || '';
const direccion = p.address_line || '';
const locality = p.locality || '';
const province = p.province || '';
const postal = p.postal_code || '';
const product = p.product_title || '';
const cartTotal = p.cart_total_ars ? money(p.cart_total_ars) : null;
const z = zoneInfo(p.zone_status || 'unknown');

const out = [];
out.push(`🔔 *Nueva solicitud — ${esc(code)}*`);
out.push('');
out.push(`*Cliente*`);
out.push(`${esc(nombre)}`);
out.push(`DNI ${esc(dni)} · ${esc(phone)}`);
if (email) out.push(esc(email));
out.push('');
out.push(`*Crédito solicitado*`);
out.push(`${esc(monto)} en ${esc(cuotas)} cuotas ${esc(freq)}`);
if (ingreso) out.push(`Ingreso declarado: ${esc(ingreso)} / mes`);
const ocVi = [occupation, housing].filter(Boolean).join(' · ');
if (ocVi) out.push(esc(ocVi));
out.push('');
out.push(`*Domicilio*`);
if (direccion) out.push(esc(direccion));
const ciudad = [locality, province].filter(Boolean).join(', ');
const ciudadLine = postal ? `${ciudad} \\(${esc(postal)}\\)` : esc(ciudad);
if (ciudad) out.push(ciudadLine);
out.push(`Estado: ${z.e} ${esc(z.label)}`);

if (product) {
  out.push('');
  out.push(`*Producto en el carrito*`);
  const prodLine = cartTotal ? `${esc(product)} — ${esc(cartTotal)}` : esc(product);
  out.push(prodLine);
}

const text = out.join('\n');

const inboxQuery = `-- Inbox solicitudes\nselect a.application_code, (c.first_name || ' ' || c.last_name) as cliente, c.dni, c.phone_e164, a.requested_amount_ars, a.requested_installments, a.zone_status, a.status, to_char(a.created_at at time zone 'America/Argentina/Buenos_Aires', 'YYYY-MM-DD HH24:MI') as fecha from credit_applications a join clients c on c.id = a.client_id order by a.created_at desc;`;
const inboxUrl = `https://supabase.com/dashboard/project/tbzlkrvmlfyqyzqkkerf/sql/new?content=${encodeURIComponent(inboxQuery)}`;

const waPhone = (phone || '').replace(/\D/g, '');
const firstName = p.first_name || '';
const waMsg = `Hola ${firstName}, te contactamos de LGA por tu solicitud de crédito ${code}`;
const waLink = waPhone ? `https://wa.me/${waPhone}?text=${encodeURIComponent(waMsg)}` : null;

const keyboard = { inline_keyboard: [] };
if (waLink) keyboard.inline_keyboard.push([{ text: `${E.speech} WhatsApp al cliente`, url: waLink }]);
keyboard.inline_keyboard.push([{ text: `${E.clipboard} Inbox solicitudes`, url: inboxUrl }]);

return [{ json: { chat_id: -1003766295782, text, parse_mode: 'MarkdownV2', reply_markup: keyboard, disable_web_page_preview: true } }];

const resp = $input.first().json;
const data = resp?.data?.draftOrderCreate || {};
const errs = data.userErrors || [];
const draft = data.draftOrder;
if (!draft || errs.length) {
  return [{ json: { ok: false, errors: errs, raw: resp } }];
}
const gid = draft.id;
const m = gid.match(/(\d+)$/);
const draft_id = m ? m[1] : '';
return [{ json: {
  ok: true,
  shopify_draft_order_id: draft_id,
  shopify_draft_order_gid: gid,
  shopify_draft_order_name: draft.name || '',
  shopify_invoice_url: draft.invoiceUrl || '',
  shopify_status: 'draft_created',
} }];
